# Dungeon Generator
import random

class Room:
    def __init__(self, w, h):
        self.w = w
        self.h = h
        self.monsters = []
        self.loot = []

    def spawn_monster(self, name):
        self.monsters.append(name)

    def add_loot(self, item):
        self.loot.append(item)

class Corridor:
    def __init__(self, start, end):
        self.start = start
        self.end = end
        self.trapped = False

    def set_trap(self):
        self.trapped = True

class Dungeon:
    def __init__(self, depth):
        self.depth = depth
        self.rooms = []
        self.corridors = []

    def gen_room(self):
        w = random.randint(3, 10)
        h = random.randint(3, 8)
        room = Room(w, h)
        self.rooms.append(room)
        return room

    def connect(self, a, b):
        c = Corridor(a, b)
        self.corridors.append(c)
        return c
